    "lessonText": "Test your understanding of the foundational concepts of AWS.",
    "questions": [
      {
        "question": "What is cloud computing?",
        "options": [
          "A type of software application",
          "Delivery of computing services over the internet",
          "A physical server in a data center",
          "A programming language"
        ],
        "correctAnswer": 1,
        "explanation": "Cloud computing is defined as the delivery of computing services over the internet."
      },
      {
        "question": "Which of the following best describes AWS services?",
        "options": [
          "Only storage solutions",
          "A wide range of services including computing power, storage, and databases",
          "A single service for web hosting",
          "Only database management"
        ],
        "correctAnswer": 1,
        "explanation": "AWS offers a wide range of services including computing power, storage, and databases."
      },
      {
        "question": "What are AWS regions?",
        "options": [
          "Physical locations where AWS data centers are located",
          "Software applications used in AWS",
          "Types of cloud computing",
          "User accounts in AWS"
        ],
        "correctAnswer": 0,
        "explanation": "AWS regions refer to the physical locations where AWS data centers are located."
      },
      {
        "question": "In the video summary, what is emphasized about AWS?",
        "options": [
          "It is a programming language",
          "It is a cloud computing platform that provides various services",
          "It only offers storage solutions",
          "It is only for large enterprises"
        ],
        "correctAnswer": 1,
        "explanation": "The video emphasizes that AWS is a cloud computing platform that provides a variety of services."
      }
    ]
  }
